class ServiceClients:
    """Lazy-initialized shared AWS service clients."""

    _dynamodb = None
    _s3 = None
    _sns = None
    _sqs = None

    @classmethod
    def dynamodb(cls):
        if cls._dynamodb is None:
            cls._dynamodb = boto3.resource('dynamodb')
        return cls._dynamodb

    @classmethod
    def s3(cls):
        if cls._s3 is None:
            cls._s3 = boto3.client('s3')
        return cls._s3

    @classmethod
    def sns(cls):
        if cls._sns is None:
            cls._sns = boto3.client('sns')
        return cls._sns

    @classmethod
    def sqs(cls):
        if cls._sqs is None:
            cls._sqs = boto3.client('sqs')
        return cls._sqs


